// VALIDACIÓN DE FORMATO DE ENTRADA - subflujo-reagenda-cita
const input = $input.first().json;

// Extraer datos
const cita_id = input.cita_id;

// VALIDACIONES
const errores = [];


// 3. VALIDAR CITA_ID (debe ser un número entero positivo o string numérico)
if (!cita_id) {
  errores.push(`ID de cita es requerido y no puede estar vacío`);
} else {
  const cita_id_num = parseInt(cita_id);
  if (isNaN(cita_id_num) || cita_id_num <= 0) {
    errores.push(`ID de cita inválido: "${cita_id}". Debe ser un número entero positivo`);
  }
}

// SI HAY ERRORES: Detener ejecución y retornar error
if (errores.length > 0) {
  return [{
    json: {
      success: false,
      error: "VALIDACIÓN_FORMATO_FALLIDA",
      errores: errores,
      datos_recibidos: {
        cita_id
      }
    }
  }];
}

// SI TODO OK: Pasar datos validados
return [{
  json: {
    success: true,
    cita_id: parseInt(cita_id)
  }
}];

// Procesar respuesta de creación de cita
const response = $input.first().json;

// Verificar si la creación fue exitosa
const exitoso = response.ResponseResult === 0;

if (exitoso) {
  // Cita creada exitosamente
  return {
    json: {
      exitoso: true,
      mensaje: "Cita eliminada exitosamente"      
    }
  };
} else {
  // Hubo un error en la creación
  return {
    json: {
      exitoso: false,
      mensaje: "Error al eliminar la cita",
      codigoError: response.ResponseResult,
      tipoError: response.ExceptionType || "Desconocido",
      detalleError: response.ExceptionMessage || "Sin detalles",
      informacionAdicional: response.ExceptionInfo || null
    }
  };
}

// Procesar salida con error de validación
const errorData = $input.first().json;

return [{
  json: {
    exitoso: false,
    tipoError: errorData.error || "ERROR_DESCONOCIDO",
    mensaje: "No se pudo eliminar la cita debido a errores de validación",
    errores: errorData.errores || [],
    cantidadErrores: (errorData.errores || []).length,
    datosRecibidos: {
      fechaCita: errorData.datos_recibidos?.fecha_cita || null,
      horaCita: errorData.datos_recibidos?.hora_cita || null,
      nombreCliente: errorData.datos_recibidos?.nombre_cliente || null,
      apellidoCliente: errorData.datos_recibidos?.apellido_cliente || null,
      modeloVehiculo: errorData.datos_recibidos?.modelo_vehiculo || null,
      patenteVehiculo: errorData.datos_recibidos?.patente_vehiculo || null,
      tallerSolicitado: errorData.datos_recibidos?.taller_solicitado || null,
      servicioSolicitado: errorData.datos_recibidos?.servicio_solicitado || null
    },
    timestamp: new Date().toISOString()
  }
}];
